import{_ as i,o as t,c as n,a2 as a}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Chapter 14: Extensibility and Plugins","description":"Building a plugin architecture with MCP protocol support, event systems, and hook patterns that make the agent extensible without modifying core code.","frontmatter":{"title":"Chapter 14: Extensibility and Plugins","description":"Building a plugin architecture with MCP protocol support, event systems, and hook patterns that make the agent extensible without modifying core code."},"headers":[],"relativePath":"learn/project/14-extensibility-and-plugins/index.md","filePath":"learn/project/14-extensibility-and-plugins/index.md"}'),l={name:"learn/project/14-extensibility-and-plugins/index.md"};function o(s,e,r,c,p,d){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="extensibility-and-plugins" tabindex="-1">Extensibility and Plugins <a class="header-anchor" href="#extensibility-and-plugins" aria-label="Permalink to &quot;Extensibility and Plugins&quot;">​</a></h1><p>A coding agent that can only do what its original authors built is limited by their imagination and time. This chapter transforms your agent from a closed system into an extensible platform. You will build the infrastructure that lets users and third-party developers add new tools, commands, and capabilities without touching the agent&#39;s core codebase.</p><p>The chapter begins with plugin architecture fundamentals -- how to define extension points, manage plugin lifecycles, and maintain stability as plugins come and go. You will implement a tool registration API that lets plugins contribute new tools at runtime, an event system for reacting to agent lifecycle events, and hook patterns for intercepting and modifying behavior. The centerpiece is a full implementation of the Model Context Protocol (MCP), the emerging standard for connecting AI agents to external tool servers, which gives your agent access to a growing ecosystem of integrations.</p><p>Beyond the basics, you will build skill loading for bundled capability packages, custom slash commands, configuration-driven extensions, and hot-reloading for rapid plugin development. Plugin isolation ensures that a misbehaving plugin cannot crash the agent, and a comprehensive testing strategy gives plugin authors confidence in their work.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Design a plugin architecture with clear extension points and lifecycle management</li><li>Implement a dynamic tool registration API for runtime tool addition</li><li>Build an event system and hook patterns for cross-cutting agent behavior</li><li>Implement the Model Context Protocol (MCP) for standardized tool server integration</li><li>Create skill loading, custom commands, and configuration-driven extensions</li><li>Ensure plugin isolation and provide a testing framework for plugin developers</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/14-extensibility-and-plugins/01-plugin-architecture.html">Plugin Architecture</a></li><li><a href="/project/14-extensibility-and-plugins/02-tool-registration-api.html">Tool Registration API</a></li><li><a href="/project/14-extensibility-and-plugins/03-event-system.html">Event System</a></li><li><a href="/project/14-extensibility-and-plugins/04-hook-patterns.html">Hook Patterns</a></li><li><a href="/project/14-extensibility-and-plugins/05-mcp-protocol-overview.html">MCP Protocol Overview</a></li><li><a href="/project/14-extensibility-and-plugins/06-mcp-implementation.html">MCP Implementation</a></li><li><a href="/project/14-extensibility-and-plugins/07-skill-loading.html">Skill Loading</a></li><li><a href="/project/14-extensibility-and-plugins/08-custom-commands.html">Custom Commands</a></li><li><a href="/project/14-extensibility-and-plugins/09-config-driven-extensions.html">Config Driven Extensions</a></li><li><a href="/project/14-extensibility-and-plugins/10-hot-reloading.html">Hot Reloading</a></li><li><a href="/project/14-extensibility-and-plugins/11-plugin-isolation.html">Plugin Isolation</a></li><li><a href="/project/14-extensibility-and-plugins/12-plugin-testing.html">Plugin Testing</a></li><li><a href="/project/14-extensibility-and-plugins/13-extension-marketplace-concepts.html">Extension Marketplace Concepts</a></li><li><a href="/project/14-extensibility-and-plugins/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 4: Tool system fundamentals and the tool trait pattern</li><li>Chapter 13: Provider abstraction patterns that inform plugin abstraction</li></ul>',10)])])}const g=i(l,[["render",o]]);export{u as __pageData,g as default};
